   120  var forceLoginParamsRegexp = regexp.MustCompile(`&?forceLogin=true`)
   121
   122  func RemoveForceLoginParams(str string) string {
   123          return forceLoginParamsRegexp.ReplaceAllString(str, "")
   124  }
