   186  func RoleAuth(roles ...org.RoleType) web.Handler {
   187          return func(c *contextmodel.ReqContext) {
   188                  ok := false
   189                  for _, role := range roles {
   190                          if role == c.OrgRole {
   191                                  ok = true
   192                                  break
   193                          }
   194                  }
   195                  if !ok {
   196                          accessForbidden(c)
   197                  }
   198          }
   199  }
