   253  // if snapshot public mode is enabled or if user has delete permission.
   254  func SnapshotPublicModeOrDelete(cfg *setting.Cfg, ac2 ac.AccessControl) web.Handler {
   255          return func(c *contextmodel.ReqContext) {
   256                  if cfg.SnapshotPublicMode {
   257                          return
