   275  // NoAuth creates a middleware that doesn't require any authentication.
   276  // If forceLogin param is set it will redirect the user to the login page.
   277  func NoAuth() web.Handler {
   278          return func(c *contextmodel.ReqContext) {
   279                  if shouldForceLogin(c) {
   280                          notAuthorized(c)
   281                          return
   282                  }
   283          }
   284  }
   285
   286  // shouldForceLogin checks if user should be enforced to login.
   287  // Returns true if forceLogin parameter is set.
   288  func shouldForceLogin(c *contextmodel.ReqContext) bool {
   289          forceLogin := false
   290          forceLoginParam, err := strconv.ParseBool(c.Req.URL.Query().Get("forceLogin"))
   291          if err == nil {
   292                  forceLogin = forceLoginParam
   293          }
   294
   295          return forceLogin
   296  }

