   192  func getTokenFromRequest(r *authn.Request) string {
   193          // api keys are only supported through http requests
   194          if r.HTTPRequest == nil {
   195                  return ""
   196          }
   197
   198          header := r.HTTPRequest.Header.Get("Authorization")
   199
   200          if strings.HasPrefix(header, bearerPrefix) {
   201                  return strings.TrimPrefix(header, bearerPrefix)
   202          }
   203          if strings.HasPrefix(header, basicPrefix) {
   204                  username, password, err := util.DecodeBasicAuthHeader(header)
   205                  if err == nil && username == "api_key" {
   206                          return password
   207                  }
   208          }
   209          return ""
   210  }
   211
   212  func validateApiKey(orgID int64, key *apikey.APIKey) error {
   213          if key.Expires != nil && *key.Expires <= time.Now().Unix() {
   214                  return errAPIKeyExpired.Errorf("API key has expired")
   215          }
   216
   217          if key.IsRevoked != nil && *key.IsRevoked {
   218                  return errAPIKeyRevoked.Errorf("Api key is revoked")
   219          }
   220
   221          if orgID != key.OrgID {
   222                  return errAPIKeyOrgMismatch.Errorf("API does not belong in Organization")
   223          }
   224
   225          // plain API keys are no longer supported so an error is returned if the api key doesn't belong to a service account
   226          if key.ServiceAccountId == nil || *key.ServiceAccountId < 1 {
   227                  return errAPIKeyInvalid.Errorf("API key does not belong to a service account")
   228          }
   229
   230          return nil
   231  }
   232
   233  func newServiceAccountIdentity(key *apikey.APIKey) *authn.Identity {
   234          return &authn.Identity{
   235                  ID:              strconv.FormatInt(*key.ServiceAccountId, 10),
   236                  Type:            claims.TypeServiceAccount,
   237                  OrgID:           key.OrgID,
   238                  AuthenticatedBy: login.APIKeyAuthModule,
   239                  ClientParams:    authn.ClientParams{FetchSyncedUser: true, SyncPermissions: true},
   240          }
   241  }
   242
   243  func shouldUpdateLastUsedAt(key *apikey.APIKey) bool {
   244          return key.LastUsedAt == nil || time.Since(*key.LastUsedAt) > 5*time.Minute
   245  }

1  package apikeygen
     2
     3  import (
     4          "encoding/base64"
     5          "encoding/json"
     6
     7          "github.com/grafana/grafana/pkg/components/satokengen"
     8          "github.com/grafana/grafana/pkg/util"
     9  )
    10
    11  type KeyGenResult struct {
    12          HashedKey    string
    13          ClientSecret string
    14  }
    15
    16  type ApiKeyJson struct {
    17          Key   string `json:"k"`
    18          Name  string `json:"n"`
    19          OrgId int64  `json:"id"`
    20  }
    21
    22  func New(orgId int64, name string) (KeyGenResult, error) {
    23          result := KeyGenResult{}
    24
    25          jsonKey := ApiKeyJson{}
    26          jsonKey.OrgId = orgId
    27          jsonKey.Name = name
    28          var err error
    29          jsonKey.Key, err = util.GetRandomString(32)
    30          if err != nil {
    31                  return result, err
    32          }
    33
    34          result.HashedKey, err = util.EncodePassword(jsonKey.Key, name)
    35          if err != nil {
    36                  return result, err
    37          }
    38
    39          jsonString, err := json.Marshal(jsonKey)
    40          if err != nil {
    41                  return result, err
    42          }
    43
    44          result.ClientSecret = base64.StdEncoding.EncodeToString(jsonString)
    45          return result, nil
    46  }
    47
    48  func Decode(keyString string) (*ApiKeyJson, error) {
    49          jsonString, err := base64.StdEncoding.DecodeString(keyString)
    50          if err != nil {
    51                  return nil, satokengen.ErrInvalidApiKey
    52          }
    53
    54          var keyObj ApiKeyJson
    55          err = json.Unmarshal(jsonString, &keyObj)
    56          if err != nil {
    57                  return nil, satokengen.ErrInvalidApiKey
    58          }
    59
    60          return &keyObj, nil
    61  }
    62
    63  func IsValid(key *ApiKeyJson, hashedKey string) (bool, error) {
    64          check, err := util.EncodePassword(key.Key, key.Name)
    65          if err != nil {
    66                  return false, err
    67          }
    68          return check == hashedKey, nil
    69  }

