   401  // scopeParams holds the parameters used to fill in scope templates
   402  type scopeParams struct {
   403          OrgID     int64
   404          URLParams map[string]string
   405  }
   406
   407  // scopeInjector inject request params into the templated scopes. e.g. "settings:" + eval.Parameters(":id")
   408  func scopeInjector(params scopeParams) ScopeAttributeMutator {
   409          return func(_ context.Context, scope string) ([]string, error) {
   410                  tmpl, err := template.New("scope").Parse(scope)
   411                  if err != nil {
   412                          return nil, err
   413                  }
   414                  var buf bytes.Buffer
   415                  if err = tmpl.Execute(&buf, params); err != nil {
   416                          return nil, err
   417                  }
   418                  return []string{buf.String()}, nil
   419          }
   420  }

1  package satokengen
     2
     3  import (
     4          "encoding/hex"
     5          "errors"
     6          "hash/crc32"
     7          "strings"
     8
     9          "github.com/grafana/grafana/pkg/util"
    10  )
    11
    12  const GrafanaPrefix = "gl"
    13
    14  var ErrInvalidApiKey = errors.New("invalid API key")
    15
    16  type KeyGenResult struct {
    17          HashedKey    string
    18          ClientSecret string
    19  }
    20
    21  type PrefixedKey struct {
    22          ServiceID string
    23          Secret    string
    24          Checksum  string
    25  }
    26
    27  func (p *PrefixedKey) Hash() (string, error) {
    28          hash, err := util.EncodePassword(p.Secret, p.Checksum)
    29          if err != nil {
    30                  return "", err
    31          }
    32          return hash, nil
    33  }
    34
    35  func (p *PrefixedKey) key() string {
    36          return GrafanaPrefix + p.ServiceID + "_" + p.Secret
    37  }
    38
    39  func (p *PrefixedKey) CalculateChecksum() string {
    40          checksum := crc32.ChecksumIEEE([]byte(p.key()))
    41          //checksum to []byte
    42          checksumBytes := make([]byte, 4)
    43          checksumBytes[0] = byte(checksum)
    44          checksumBytes[1] = byte(checksum >> 8)
    45          checksumBytes[2] = byte(checksum >> 16)
    46          checksumBytes[3] = byte(checksum >> 24)
    47
    48          return hex.EncodeToString(checksumBytes)
    49  }
    50
    51  func (p *PrefixedKey) String() string {
    52          return p.key() + "_" + p.Checksum
    53  }
    54
    55  func New(serviceID string) (KeyGenResult, error) {
    56          result := KeyGenResult{}
    57
    58          secret, err := util.GetRandomString(32)
    59          if err != nil {
    60                  return result, err
    61          }
    62
    63          key := PrefixedKey{ServiceID: serviceID, Secret: secret, Checksum: ""}
    64          key.Checksum = key.CalculateChecksum()
    65
    66          result.HashedKey, err = key.Hash()
    67          if err != nil {
    68                  return result, err
    69          }
    70
    71          result.ClientSecret = key.String()
    72
    73          return result, nil
    74  }
    75
    76  func Decode(keyString string) (*PrefixedKey, error) {
    77          if !strings.HasPrefix(keyString, GrafanaPrefix) {
    78                  return nil, ErrInvalidApiKey
    79          }
    80
    81          parts := strings.Split(keyString, "_")
    82          if len(parts) != 3 {
    83                  return nil, ErrInvalidApiKey
    84          }
    85
    86          key := &PrefixedKey{
    87                  ServiceID: strings.TrimPrefix(parts[0], GrafanaPrefix),
    88                  Secret:    parts[1],
    89                  Checksum:  parts[2],
    90          }
    91          if key.CalculateChecksum() != key.Checksum {
    92                  return nil, ErrInvalidApiKey
    93          }
    94
    95          return key, nil
    96  }

