    31                  }
    32
    33                  sess = sess.Join("inner", quotedUser, quotedUser+".id = api_key.service_account_id").
    34                          Asc("api_key.name")
    35
    36                  if err := sess.Find(&result); err != nil {
    37                          return fmt.Errorf("%s: %w", "list token error", err)
