   321  // UseGlobalOrgFromRequestData returns global org if `global` flag is set or the org where user is logged in.
   322  // If RBACSingleOrganization is set, the org where user is logged in is returned - this is intended only for cloud workflows, where instances are limited to a single organization.
   323  func UseGlobalOrgFromRequestData(cfg *setting.Cfg) OrgIDGetter {
   324          return func(c *contextmodel.ReqContext) (int64, error) {
   325                  query, err := getOrgQueryFromRequest(c)
   326                  if err != nil {
   327                          return NoOrgID, err
   328                  }
   329
   330                  // We only check permissions in the global organization if we are not running a SingleOrganization setup
   331                  // That allows Organization Admins to modify global roles and make global assignments.
   332                  if query.Global && !cfg.RBAC.SingleOrganization {
   333                          return GlobalOrgID, nil
   334                  }
   335
   336                  return c.GetOrgID(), nil
   337          }
   338  }
   339
   340  // UseGlobalOrgFromRequestParams returns global org if `global` flag is set or the org where user is logged in.
   341  func UseGlobalOrgFromRequestParams(cfg *setting.Cfg) OrgIDGetter {
   342          return func(c *contextmodel.ReqContext) (int64, error) {
   343                  // We only check permissions in the global organization if we are not running a SingleOrganization setup
   344                  // That allows Organization Admins to modify global roles and make global assignments, and is intended for use in hosted Grafana.
   345                  if c.QueryBool("global") && !cfg.RBAC.SingleOrganization {
   346                          return GlobalOrgID, nil
   347                  }
   348
   349                  return c.GetOrgID(), nil
   350          }
   351  }
   352
   353  func getOrgQueryFromRequest(c *contextmodel.ReqContext) (*QueryWithOrg, error) {
   354          query := &QueryWithOrg{}
   355
   356          req, err := CloneRequest(c.Req)
   357          if err != nil {
   358                  return nil, err
   359          }
   360
   361          if err := web.Bind(req, query); err != nil {
   362                  if err.Error() == "unexpected EOF" {
   363                          return nil, fmt.Errorf("%w: unexpected end of JSON input", ErrInvalidRequestBody)
   364                  }
   365                  return nil, ErrInvalidRequest.Errorf("error parsing request: %w", err)
   366          }
   367
   368          return query, nil
   369  }
   370
   371  // CloneRequest creates request copy including request body
   372  func CloneRequest(req *http.Request) (*http.Request, error) {
   373          // Get copy of body to prevent error when reading closed body in request handler
   374          bodyCopy, err := CopyRequestBody(req)
   375          if err != nil {
   376                  return nil, err
   377          }
   378          reqCopy := req.Clone(req.Context())
   379          reqCopy.Body = bodyCopy
   380          return reqCopy, nil
   381  }
   382
   383  // CopyRequestBody returns copy of request body and keeps the original one to prevent error when reading closed body
   384  func CopyRequestBody(req *http.Request) (io.ReadCloser, error) {
   385          if req.Body == nil {
   386                  return nil, nil
   387          }
   388
   389          body := req.Body
   390          var buf bytes.Buffer
   391          if _, err := buf.ReadFrom(body); err != nil {
   392                  return nil, err
   393          }
   394          if err := body.Close(); err != nil {
   395                  return nil, err
   396          }
   397          req.Body = io.NopCloser(&buf)
   398          return io.NopCloser(bytes.NewReader(buf.Bytes())), nil
   399  }
   400
   401  // scopeParams holds the parameters used to fill in scope templates
   402  type scopeParams struct {
   403          OrgID     int64
   404          URLParams map[string]string
   405  }
   406
   407  // scopeInjector inject request params into the templated scopes. e.g. "settings:" + eval.Parameters(":id")
   408  func scopeInjector(params scopeParams) ScopeAttributeMutator {
   409          return func(_ context.Context, scope string) ([]string, error) {
   410                  tmpl, err := template.New("scope").Parse(scope)
   411                  if err != nil {
   412                          return nil, err
   413                  }
   414                  var buf bytes.Buffer
   415                  if err = tmpl.Execute(&buf, params); err != nil {
   416                          return nil, err
   417                  }
   418                  return []string{buf.String()}, nil
   419          }
   420  }

