     9  const (
    10          maxPrefixParts = 2
    11  )
    12
    13  // SplitScope returns kind, attribute and Identifier
    14  func SplitScope(scope string) (string, string, string) {
    15          if scope == "" {
    16                  return "", "", ""
    17          }
    18
    19          fragments := strings.Split(scope, ":")
    20          switch l := len(fragments); l {
    21          case 1: // Splitting a wildcard scope "*" -> kind: "*"; attribute: "*"; identifier: "*"
    22                  return fragments[0], fragments[0], fragments[0]
    23          case 2: // Splitting a wildcard scope with specified kind "dashboards:*" -> kind: "dashboards"; attribute: "*"; identifier: "*"
    24                  return fragments[0], fragments[1], fragments[1]
    25          default: // Splitting a scope with all fields specified "dashboards:uid:my_dash" -> kind: "dashboards"; attribute: "uid"; identifier: "my_dash"
    26                  return fragments[0], fragments[1], strings.Join(fragments[2:], ":")
    27          }
    28  }
    29
    30  func ParseScopeID(scope string) (int64, error) {
    31          id, err := strconv.ParseInt(ScopeSuffix(scope), 10, 64)
    32          if err != nil {
    33                  return 0, ErrInvalidScope
    34          }
    35          return id, nil
    36  }
    37
    38  func ParseScopeUID(scope string) (string, error) {
    39          uid := ScopeSuffix(scope)
    40          if len(uid) == 0 {
    41                  return "", ErrInvalidScope
    42          }
    43          return uid, nil
    44  }
    45
    46  func ScopeSuffix(scope string) string {
    47          return scope[len(ScopePrefix(scope)):]
    48  }
    49
    50  func GetResourceScope(resource string, resourceID string) string {
    51          return Scope(resource, "id", resourceID)
    52  }
    53
    54  func GetResourceScopeUID(resource string, resourceID string) string {
    55          return Scope(resource, "uid", resourceID)
    56  }
    57
    58  func GetResourceScopeName(resource string, resourceID string) string {
    59          return Scope(resource, "name", resourceID)
    60  }
    61
    62  func GetResourceScopeType(resource string, typeName string) string {
    63          return Scope(resource, "type", typeName)
    64  }
    65
    66  func GetResourceAllScope(resource string) string {
    67          return Scope(resource, "*")
    68  }
    69
    70  func GetResourceAllIDScope(resource string) string {
    71          return Scope(resource, "id", "*")
    72  }
    73
    74  // Scope builds scope from parts
    75  // e.g. Scope("users", "*") return "users:*"
    76  func Scope(parts ...string) string {
    77          b := strings.Builder{}
    78          for i, c := range parts {
    79                  if i != 0 {
    80                          b.WriteRune(':')
    81                  }
    82                  b.WriteString(c)
    83          }
    84          return b.String()
    85  }
    86
    87  // Parameter returns injectable scope part, based on URL parameters.
    88  // e.g. Scope("users", Parameter(":id")) or "users:" + Parameter(":id")
    89  func Parameter(key string) string {
    90          return fmt.Sprintf(`{{ index .URLParams "%s" }}`, key)
    91  }
    92
    93  // Field returns an injectable scope part for selected fields from the request's context available in accesscontrol.ScopeParams.
    94  // e.g. Scope("orgs", Parameter("OrgID")) or "orgs:" + Parameter("OrgID")
    95  func Field(key string) string {
    96          return fmt.Sprintf(`{{ .%s }}`, key)
    97  }
    98
    99  // ScopePrefix returns the prefix associated to a given scope
   100  // we assume prefixes are all in the form <resource>:<attribute>:<value>
   101  // ex: "datasources:name:test" returns "datasources:name:"
   102  func ScopePrefix(scope string) string {
   103          parts := strings.Split(scope, ":")
   104          // We assume prefixes don't have more than maxPrefixParts parts
   105          if len(parts) > maxPrefixParts {
   106                  parts = append(parts[:maxPrefixParts], "")
   107          }
   108          return strings.Join(parts, ":")
   109  }
