   132  // GetResourceScope returns scope that has the format "<rootScope>:id:<resourceID>"
   133  func (s scopeProviderImpl) GetResourceScope(resourceID string) string {
   134          return GetResourceScope(s.root, resourceID)
   135  }
   136
   137  // GetResourceScopeUID returns scope that has the format "<rootScope>:uid:<resourceID>"
   138  func (s scopeProviderImpl) GetResourceScopeUID(resourceID string) string {
   139          return GetResourceScopeUID(s.root, resourceID)
   140  }
   141
   142  // GetResourceScopeName returns scope that has the format "<rootScope>:name:<resourceID>"
   143  func (s scopeProviderImpl) GetResourceScopeName(resourceID string) string {
   144          return GetResourceScopeName(s.root, resourceID)
   145  }
   146
   147  // GetResourceScopeType returns scope that has the format "<rootScope>:type:<typeName>"
   148  func (s scopeProviderImpl) GetResourceScopeType(typeName string) string {
   149          return GetResourceScopeType(s.root, typeName)
   150  }
   151
   152  // GetResourceAllScope returns scope that has the format "<rootScope>:*"
   153  func (s scopeProviderImpl) GetResourceAllScope() string {
   154          return GetResourceAllScope(s.root)
   155  }
   156
   157  // GetResourceAllIDScope returns scope that has the format "<rootScope>:id:*"
   158  func (s scopeProviderImpl) GetResourceAllIDScope() string {
   159          return GetResourceAllIDScope(s.root)
   160  }
   161
   162  func WildcardsFromPrefix(prefix string) Wildcards {
   163          return WildcardsFromPrefixes([]string{prefix})
   164  }
   165
   166  // WildcardsFromPrefixes generates valid wildcards from prefixes
   167  // datasource:uid: => "*", "datasource:*", "datasource:uid:*"
   168  func WildcardsFromPrefixes(prefixes []string) Wildcards {
   169          var b strings.Builder
   170          wildcards := Wildcards{"*"}
   171          for _, prefix := range prefixes {
   172                  parts := strings.Split(prefix, ":")
   173                  for _, p := range parts {
   174                          if p == "" {
   175                                  continue
   176                          }
   177                          b.WriteString(p)
   178                          b.WriteRune(':')
   179                          wildcards = append(wildcards, b.String()+"*")
   180                  }
   181                  b.Reset()
   182          }
   183          return wildcards
   184  }
   185
   186  type Wildcards []string
   187
   188  // Contains check if wildcards contains scope
   189  func (wildcards Wildcards) Contains(scope string) bool {
   190          for _, w := range wildcards {
   191                  if scope == w {
   192                          return true
   193                  }
   194          }
   195          return false
   196  }
   197
   198  func isWildcard(scope string) bool {
   199          return scope == "*" || strings.HasSuffix(scope, ":*")
   200  }

