    11
    12  var logger = log.New("accesscontrol.evaluator")
    13
    14  type CheckerFn func(action string, scopes ...string) (bool, error)
    15
    16  type Evaluator interface {
    17          // Evaluate permissions that are grouped by action
    18          Evaluate(permissions map[string][]string) bool
    19          // EvaluateCustom allows to perform evaluation with custom check function
    20          EvaluateCustom(fn CheckerFn) (bool, error)
    21          // MutateScopes executes a sequence of ScopeModifier functions on all embedded scopes of an evaluator and returns a new Evaluator
    22          MutateScopes(ctx context.Context, mutate ScopeAttributeMutator) (Evaluator, error)
    23          // String returns a string representation of permission required by the evaluator
    24          fmt.Stringer
    25          fmt.GoStringer
    26  }
    27
    28  var _ Evaluator = new(permissionEvaluator)
    29
    30  // EvalPermission returns an evaluator that will require at least one of passed scopes to match
    31  func EvalPermission(action string, scopes ...string) Evaluator {
    32          return permissionEvaluator{Action: action, Scopes: scopes}
    33  }
    34
    35  type permissionEvaluator struct {
    36          Action string
    37          Scopes []string
    38  }
    39
    40  func (p permissionEvaluator) Evaluate(permissions map[string][]string) bool {
    41          userScopes, ok := permissions[p.Action]
    42          if !ok {
    43                  return false
    44          }
    45
    46          if len(p.Scopes) == 0 {
    47                  return true
    48          }
    49
    50          for _, target := range p.Scopes {
    51                  for _, scope := range userScopes {
    52                          if match(scope, target) {
    53                                  return true
    54                          }
    55                  }
    56          }
    57
    58          return false
    59  }
    60
    61  func match(scope, target string) bool {
    62          if scope == "" {
    63                  return false
    64          }
    65
    66          if !ValidateScope(scope) {
    67                  logger.Error(
    68                          "invalid scope",
    69                          "scope", scope,
    70                          "reason", "scopes should not contain meta-characters like * or ?, except in the last position",
    71                  )
    72                  return false
    73          }
    74
    75          prefix, last := scope[:len(scope)-1], scope[len(scope)-1]
    76          //Prefix match
    77          if last == '*' {
    78                  if strings.HasPrefix(target, prefix) {
    79                          logger.Debug("Matched scope", "user scope", scope, "target scope", target)
    80                          return true
    81                  }
    82          }
    83
    84          return scope == target
    85  }
    86
    87  func (p permissionEvaluator) EvaluateCustom(fn CheckerFn) (bool, error) {
    88          if len(p.Scopes) == 0 {
    89                  return fn(p.Action, "")
    90          }
    91
    92          matches, err := fn(p.Action, p.Scopes...)
    93          if err != nil {
    94                  return false, err
    95          }
    96
    97          return matches, nil
    98  }
    99
   100  func (p permissionEvaluator) MutateScopes(ctx context.Context, mutate ScopeAttributeMutator) (Evaluator, error) {
   101          ctx, span := tracer.Start(ctx, "accesscontrol.permissionEvaluatorMutateScopes")
   102          defer span.End()
   103
   104          if p.Scopes == nil {
   105                  return EvalPermission(p.Action), nil
   106          }
   107
   108          resolved := false
   109          scopes := make([]string, 0, len(p.Scopes))
   110          for _, scope := range p.Scopes {
   111                  mutated, err := mutate(ctx, scope)
   112                  if err != nil {
   113                          if errors.Is(err, ErrResolverNotFound) {
   114                                  scopes = append(scopes, mutated...)
   115                                  continue
   116                          }
   117                          return nil, err
   118                  }
   119                  resolved = true
   120                  scopes = append(scopes, mutated...)
   121          }
   122
   123          if !resolved {
   124                  return nil, ErrResolverNotFound
   125          }
   126
   127          return EvalPermission(p.Action, scopes...), nil
   128  }
   129
   130  func (p permissionEvaluator) String() string {
   131          return p.Action
   132  }
   133
   134  func (p permissionEvaluator) GoString() string {
   135          return fmt.Sprintf("action:%s scopes:%s", p.Action, strings.Join(p.Scopes, ", "))
   136  }
