    90  func writeRedirectCookie(c *contextmodel.ReqContext) {
    91          redirectTo := c.Req.RequestURI
    92          if setting.AppSubUrl != "" && !strings.HasPrefix(redirectTo, setting.AppSubUrl) {
    93                  redirectTo = setting.AppSubUrl + c.Req.RequestURI
    94          }
    95
    96          if redirectTo == "/" {
    97                  return
    98          }
    99
   100          // remove any forceLogin=true params
   101          redirectTo = RemoveForceLoginParams(redirectTo)
   102          cookies.WriteCookie(c.Resp, "redirect_to", url.QueryEscape(redirectTo), 0, nil)
   103  }
   104
   105  func getRedirectToQueryParam(c *contextmodel.ReqContext) string {
   106          redirectTo := c.Req.RequestURI
   107          if setting.AppSubUrl != "" && strings.HasPrefix(redirectTo, setting.AppSubUrl) {
   108                  redirectTo = strings.TrimPrefix(redirectTo, setting.AppSubUrl)
   109          }
   110
   111          if redirectTo == "/" {
   112                  return ""
   113          }
   114
   115          // remove any forceLogin=true params
   116          redirectTo = RemoveForceLoginParams(redirectTo)
   117          return "?redirectTo=" + url.QueryEscape(redirectTo)
   118  }
