        "prefix": "gl",
        "structure": "gl<serviceID>_<32-char-random-secret>_<8-char-hex-crc32-checksum>",
        "example": "glsa_yscW25imSKJIuav8zF37RZmnbiDvB05G_fcaaf58a",
        "hash_stored": "EncodePassword(secret, checksum)  — PBKDF2-SHA256",
        "lookup": "GetAPIKeyByHash(hash)  — direct hash lookup"
      },
      "legacy": {
