        "key VARCHAR(190) NOT NULL  — stores the hashed key",
        "role NVARCHAR(255) NOT NULL",
        "created DATETIME NOT NULL",
        "updated DATETIME NOT NULL",
        "expires BIGINT NULL  — Unix timestamp; NULL means no expiration",
        "service_account_id BIGINT NULL  — FK to user.id; NULL for legacy plain API keys",
